CREATE EXTENSION IF NOT EXISTS pgcrypto;
CREATE TABLE users(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),email TEXT UNIQUE NOT NULL,password_hash TEXT NOT NULL,display_name TEXT NOT NULL,created_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE organizations(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),name TEXT NOT NULL,slug TEXT UNIQUE NOT NULL);
CREATE TABLE projects(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),organization_id UUID NOT NULL REFERENCES organizations(id) ON DELETE CASCADE,name TEXT NOT NULL,UNIQUE(organization_id,name));
CREATE TABLE retry_policies(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),project_id UUID NOT NULL REFERENCES projects(id) ON DELETE CASCADE,name TEXT NOT NULL,strategy TEXT NOT NULL CHECK(strategy IN('FIXED','LINEAR','EXPONENTIAL')),max_attempts INT NOT NULL CHECK(max_attempts>0),base_delay_seconds INT NOT NULL,max_delay_seconds INT NOT NULL);
CREATE TABLE queues(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),project_id UUID NOT NULL REFERENCES projects(id) ON DELETE CASCADE,retry_policy_id UUID REFERENCES retry_policies(id) ON DELETE SET NULL,name TEXT NOT NULL,paused BOOLEAN NOT NULL DEFAULT false,concurrency_limit INT NOT NULL CHECK(concurrency_limit>0),UNIQUE(project_id,name));
CREATE TABLE workers(id UUID PRIMARY KEY,name TEXT NOT NULL,status TEXT NOT NULL,capacity INT NOT NULL,started_at TIMESTAMPTZ NOT NULL,last_heartbeat_at TIMESTAMPTZ NOT NULL);
CREATE TABLE worker_heartbeats(id BIGSERIAL PRIMARY KEY,worker_id UUID NOT NULL REFERENCES workers(id) ON DELETE CASCADE,active_jobs INT NOT NULL,recorded_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE jobs(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),queue_id UUID NOT NULL REFERENCES queues(id) ON DELETE RESTRICT,name TEXT NOT NULL,payload JSONB NOT NULL,status TEXT NOT NULL,priority INT NOT NULL DEFAULT 0,attempts INT NOT NULL DEFAULT 0,max_attempts INT NOT NULL DEFAULT 3,available_at TIMESTAMPTZ NOT NULL DEFAULT now(),claimed_by UUID REFERENCES workers(id) ON DELETE SET NULL,lease_expires_at TIMESTAMPTZ,idempotency_key TEXT,created_at TIMESTAMPTZ NOT NULL DEFAULT now(),updated_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE UNIQUE INDEX uq_idem ON jobs(queue_id,idempotency_key) WHERE idempotency_key IS NOT NULL;
CREATE INDEX ix_claim ON jobs(queue_id,status,available_at,priority DESC,created_at);
CREATE INDEX ix_lease ON jobs(lease_expires_at) WHERE status IN('CLAIMED','RUNNING');
CREATE TABLE scheduled_jobs(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),queue_id UUID NOT NULL REFERENCES queues(id) ON DELETE CASCADE,name TEXT NOT NULL,payload JSONB NOT NULL,cron_expression TEXT NOT NULL,timezone TEXT NOT NULL DEFAULT 'UTC',next_run_at TIMESTAMPTZ NOT NULL,enabled BOOLEAN NOT NULL DEFAULT true);
CREATE INDEX ix_schedule ON scheduled_jobs(next_run_at) WHERE enabled;
CREATE TABLE job_executions(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),job_id UUID NOT NULL REFERENCES jobs(id) ON DELETE CASCADE,worker_id UUID REFERENCES workers(id) ON DELETE SET NULL,attempt_number INT NOT NULL,status TEXT NOT NULL,started_at TIMESTAMPTZ,finished_at TIMESTAMPTZ,duration_ms BIGINT,error_code TEXT,error_message TEXT,UNIQUE(job_id,attempt_number));
CREATE TABLE retry_history(id BIGSERIAL PRIMARY KEY,job_id UUID NOT NULL REFERENCES jobs(id) ON DELETE CASCADE,attempt_number INT NOT NULL,strategy TEXT NOT NULL,delay_seconds INT NOT NULL,reason TEXT,scheduled_for TIMESTAMPTZ NOT NULL,created_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE job_logs(id BIGSERIAL PRIMARY KEY,job_id UUID NOT NULL REFERENCES jobs(id) ON DELETE CASCADE,execution_id UUID REFERENCES job_executions(id) ON DELETE CASCADE,level TEXT NOT NULL,message TEXT NOT NULL,logged_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE INDEX ix_logs ON job_logs(job_id,logged_at);
CREATE TABLE dead_letter_entries(id UUID PRIMARY KEY DEFAULT gen_random_uuid(),job_id UUID NOT NULL UNIQUE REFERENCES jobs(id) ON DELETE CASCADE,final_error TEXT NOT NULL,failed_at TIMESTAMPTZ NOT NULL DEFAULT now(),replayed_at TIMESTAMPTZ);
